import Spacings from '@dynatrace/strato-design-tokens/spacings';

/* Constants for rendering the calendar view */
export const NUMBER_OF_WEEKDAYS = 7;
export const NUMBER_OF_MONTHS_PER_ROW = 3;
export const NUMBER_OF_YEARS_PER_ROW = 4;
export const NUMBER_OF_MONTHS = 12;
// The calendar uses a fixed height to avoid layout jumps, with a maximum of 6 rows.
export const NUMBER_OF_WEEK_ROWS = 6;
export const NUMBER_OF_MONTH_ROWS = 4;
export const NUMBER_OF_YEAR_ROWS = 6;
export const COLUMNS_GAP = Spacings.Size4;
/**
 * The view for switching the current year should use the same amount of rows as
 * the date view, but only 4 columns. This means years displayed = NUMBER_OF_YEAR_ROWS * 4
 */
export const NUMBER_OF_YEARS = NUMBER_OF_YEAR_ROWS * 4;
/** The list of years should initially start at the current year - offset. */
export const YEARS_RANGE_START_OFFSET = -5;
/**
 * @internal
 */
export type CalendarType = 'single' | 'range';
